const kpi = $('HTTP — KPI offmarket').first().json;
const captActive = ($('HTTP — Em captação activa').first().json.data || []);
const meetings = ($('HTTP — Reuniões agendadas').first().json.data || []);

const offmarket = kpi.offmarket || {};
const partners = kpi.institutional_partners || {};

// Source breakdown summary
const srcBreakdown = (offmarket.by_source || []).slice(0,5)
  .map(s => `${s.source}: ${s.count}`).join(' · ') || '—';

// Status breakdown
const statusBreakdown = (offmarket.by_status || [])
  .filter(s => !['closed_lost','not_interested'].includes(s.status))
  .map(s => `${s.status}: ${s.count}`).join(' · ') || '—';

// Pipeline value
const pipelineValue = captActive
  .reduce((sum, l) => sum + (l.price_estimate || l.price_ask || 0), 0);
const pipelineFormatted = pipelineValue > 0 
  ? '€' + (pipelineValue / 1_000_000).toFixed(1) + 'M' 
  : '—';

// Top captação leads
const topCaptacao = captActive.slice(0,3)
  .map((l,i) => `${i+1}. ${l.nome} — ${l.tipo_ativo||'?'} ${l.cidade?'('+l.cidade+')':''} — €${l.price_estimate?(l.price_estimate/1000).toFixed(0)+'K':'?'}`)
  .join('\n');

const weekNumber = Math.ceil(new Date().getDate() / 7);

return [{ json: {
  total: offmarket.total || 0,
  new_this_week: offmarket.new_this_week || 0,
  high_score: offmarket.high_score || 0,
  avg_score: offmarket.avg_score ? parseFloat(offmarket.avg_score).toFixed(0) : '—',
  captation_active: captActive.length,
  meetings_scheduled: meetings.length,
  pipeline_value: pipelineFormatted,
  partners_total: partners.total || 0,
  src_breakdown: srcBreakdown,
  status_breakdown: statusBreakdown,
  top_captacao: topCaptacao || '— sem captações activas —',
  week: weekNumber,
  year: new Date().getFullYear()
}}];
